import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"55. Long Service Leave","description":"","frontmatter":{"title":"55. Long Service Leave","eba":"Medical Specialists 2022-2026","topics":["leave","long-service-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/55-long-service-leave.md","filePath":"ebas/medical-specialists/leave/55-long-service-leave.md"}'),r={name:"ebas/medical-specialists/leave/55-long-service-leave.md"};function i(s,e,c,l,p,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_55-long-service-leave" tabindex="-1">55. Long Service Leave <a class="header-anchor" href="#_55-long-service-leave" aria-label="Permalink to &quot;55. Long Service Leave&quot;">​</a></h1><p><strong>55.1</strong> Definitions</p><p>The following meanings shall apply to the terms referred to below for the purposes of this clause unless a contrary intention is apparent:</p><p><strong>(a)</strong> Internal Locum means a Doctor classified or employed as such at the time they apply for or commence long service leave;</p><p><strong>(b)</strong> Fractional Doctor means a Doctor classified or employed as such at the time they apply for or commence long service leave;</p><p><strong>(c)</strong> Full-time Doctor means a Doctor classified or employed as such at the time they apply for or commence long service leave;</p><p><strong>(d)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(e)</strong> Month means a calendar month.</p><p><strong>(f)</strong> Pay means:</p><p><strong>(i)</strong> for a Full-time Doctor, remuneration for a Doctor&#39;s normal weekly hours of work calculated at their ordinary time rate of pay at the time the leave is taken or (if they die before the completion of leave so taken) as at the time of their death, and will include the amount of any increase to the Doctor&#39;s ordinary time rate of pay which occurred during the period of leave;</p><p><strong>(ii)</strong> for a Fractional Doctor means the remuneration calculated on the average of the Doctor&#39;s ordinary hours of work applying over the two years of employment immediately preceding the taking of leave; and</p><p><strong>(iii)</strong> for an Internal Locum Doctor, means the remuneration for the Doctor&#39;s normal weekly hours of work at their ordinary pay calculated in accordance with sections 15 and 16 of the LSL Act,</p><p>save that, in the case of Fractional Doctors and Internal Locum Doctors, any averaging of normal weekly hours will be taken to exclude periods of employment other than as a Doctor covered by this Agreement (or its predecessors).</p><p><strong>(g)</strong> Transfer of business occurs in the circumstances described at section 311 of the Act.</p><p><strong>55.2</strong> Entitlement</p><p><strong>(a)</strong> Doctors are entitled to:</p><p><strong>(i)</strong> six months&#39; long service leave with Pay on completion of fifteen years of Continuous Service (as defined at subclause 55.3(a)(ii)); and</p><p><strong>(ii)</strong> thereafter an additional two months&#39; long service leave with Pay on completion of each additional five years of Continuous Service (as defined at subclause 55.3(a)(ii)).</p><p><strong>(b)</strong> Subject to subclause 55.4(d), the entitlement under subclause 55.2(a) may be taken in advance on a pro rata basis if the Doctor has accrued Continuous Service of at least:</p><p><strong>(i)</strong> 10 years; or</p><p><strong>(ii)</strong> from 1 July 2021/2022, 9 years; or</p><p><strong>(iii)</strong> from 1 July 2022/2023, 8 years; or</p><p><strong>(iv)</strong> from 1 July 2023/2024, 7 years.</p><p><strong>55.3</strong> Calculating Continuous Service</p><p><strong>(a)</strong> Definitions:</p><p><strong>(i)</strong> Allowable Period of Absence means the greater of:</p><p>A. five weeks in addition to the total period of paid annual leave and/or personal leave that the Doctor actually receives on termination, or for which they are paid in lieu; or</p><p>B. such longer period of absence equivalent to and for the purpose of parental leave under the NES.</p><p><strong>(ii)</strong> Continuous Service means continuous service with the same Health Service plus any prior continuous service of six months or more with one or more Institutions or Statutory Bodies directly associated with such Institutions.</p><p><strong>(iii)</strong> Continuous Internal Locum Employment means, for the purpose of subclause 55.3(b), a period or periods of employment as an Internal Locum Doctor) with the same Health Service that are taken to be continuous, because one of the following applies:</p><p>A. the period starting at the end of a particular instance of employment and ending at the start of another</p><p>particular instance of employment did not exceed the greater of the Allowable Period of Absence (where applicable), or 12 weeks;</p><p>B. the Doctor had been employed by a Health Service on a regular and systematic basis and the Doctor had a reasonable expectation of being re-engaged by the same Health Service;</p><p>C. the gap between engagements was due to the terms of engagement of the Internal Locum Doctor;</p><p>D. the gap between engagements was caused by seasonal factors; or</p><p>E. the Doctor and Health Service agreed, before the start of an absence, to treat the employment as continuous despite the absence.</p><p><strong>(b)</strong> Periods that count towards Continuous Service</p><p>Service or prior service during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause 55.2(a):</p><p><strong>(i)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the Health Service if made with the intention of avoiding obligations in respect of long service leave or annual leave;</p><p><strong>(iii)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which a Doctor is receiving accident make-up pay under <a href="/eba/ebas/medical-specialists/wages/34-accident-pay.html">clause 34</a>;</p><p><strong>(iv)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(v)</strong> a period of absence on community service leave under the Act;</p><p><strong>(vi)</strong> service as part of a specialist training program accredited by a Specialist Medical College with an employer not covered by this Agreement where:</p><p>A. the break between the periods of employment is not more than two months&#39; duration or the Allowable Period of Absence (whichever is longer); and</p><p>B. the Doctor has not received payment for their long service leave benefit for that service;</p><p><strong>(vii)</strong> in the case of Doctors who commenced employment with a Victorian public Health Service after 30 November 2008, their prior service with an interstate government health service, provided that the break between ceasing employment with the interstate government health service, and commencing employment with the Victorian public Health Service, is no more than two calendar months ;</p><p><strong>(viii)</strong> in the case of unpaid absences not otherwise referenced in this subclause, subject to subclause 55.6:</p><p>A. any unpaid leave that is authorised in advance in writing by the Health Service to count as service; or</p><p>B. up to the commencement date of this Agreement, any unpaid absence from work on account of illness or injury of not more than 14 days (in the case of a Full- time Doctor) or 48 weeks (in the case of a Fractional Doctor or Internal Locum Doctor); or</p><p>C. on and from the commencement date of this Agreement:</p><p>1) any period of unpaid leave taken on account of illness or injury;</p><p>2) a period of Parental Leave, including Parental Leave that is extended under subclause 54.12; and</p><p>3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause; and</p><p><strong>(ix)</strong> in the case of Internal Locums:</p><p>A. periods of Continuous Casual Employment with the current Health Service (whether or not in a role covered by this Agreement); and</p><p>B. prior Continuous Casual Employment of six months or more that was with one or more Institutions (or Statutory Bodies directly associated with such Institutions), subject to subclauses 55.5(c) and 55.9(a), including any such periods of employment under the DIT Agreement,</p><p>save that if long service leave was already taken or paid in lieu in respect of any period referred to above, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(c)</strong> Not counted as Continuous Service but Not Breaking Continuity of Continuous Service</p><p>Unless otherwise agreed in writing in advance between the Health Service and Doctor, the following periods do not break Continuous Service but do not count towards a Doctor&#39;s Continuous Service for the purpose of calculating the Doctor&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of unpaid leave not referred to in subclause 55.3(b) (including any Parental Leave not covered by subclause 55.3(b)(i) 55.3(b)(viii)</p><p><strong>(ii)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(iii)</strong> in the case of Full-time Doctors and Fractional Doctors, any period between the engagement with one Institution or Statutory Body and another provided it is less than the Allowable Period of Absence;</p><p><strong>(iv)</strong> the dismissal of a Doctor if the Doctor is re-employed by the same Health Service within a period not exceeding two months from the date of such dismissal;</p><p><strong>(v)</strong> any absence on account of injury arising out of or in the course of their employment not covered by a period in which the Doctor is receiving accident make up pay or other paid leave;</p><p><strong>(vi)</strong> any absence that is greater than the Allowable Period of Absence that arises due to delays in obtaining the Doctor&#39;s specialist registration through AHPRA;</p><p><strong>(vii)</strong> any periods of up to 24 months&#39; unpaid leave that are taken for parental leave purposes, but that do not constitute Parental Leave (and which are not covered by subclause 55.3(b)(i) and (b)(viii)(viii); and</p><p><strong>(viii)</strong> Service that lasts less than six months with the Department, any Hospital, Benevolent Home, Community Health Centre, Society or Association that is registered under the Health Services Act.</p><p><strong>(d)</strong> Transfer of business</p><p>Where a Transfer of Business occurs, a Doctor who worked with the old Health Service and who continues in the service of the new Health Service will be entitled to count their service with the old Health Service as service with the new Health Service for the purposes of this clause.</p><p><strong>(e)</strong> Proof of sufficient aggregate of service</p><p>The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Doctor concerned. A Certificate of Service in accordance with <a href="/eba/ebas/medical-specialists/appendices/4-template-certificate-of-service.html">Appendix 4</a> will constitute acceptable proof.</p><p><strong>55.4</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken</p><p>A Doctor who is eligible to take long service leave under subclause 55.2(a) must be granted long service leave within six months of the date eligibility arose. By agreement, the taking of the leave may be postponed to such a date mutually agreed.</p><p><strong>(b)</strong> How leave is to be taken</p><p><strong>(i)</strong> Doctors may request to take long service leave as a single entitlement or in multiple separate periods, with each period being not less than:</p><p>A. in the case of Full-time Doctors, 1 week; or</p><p>B. in the case of a Fractional Doctor or casual/Internal Locum Doctors, 1 day.</p><p><strong>(ii)</strong> By agreement, Doctors may also utilise their long service leave entitlements as part of a Transition to Retirement in accordance with <a href="/eba/ebas/medical-specialists/employment/22-transition-to-retirement.html">clause 22</a>.</p><p><strong>(c)</strong> Payment for period of leave</p><p><strong>(i)</strong> Payment will be made in one of the following ways:</p><p>A. in full advance when the Doctor commences their leave;</p><p>B. at the same time as payment would have been made if the Doctor had remained on duty; or</p><p>C. in any other way agreed between the Doctor and the Health Service.</p><p><strong>(ii)</strong> Where a Doctor has been paid in advance, and an increase to the Doctor&#39;s the ordinary time rate of pay occurs during the period of long service leave taken, the Doctor will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>(d)</strong> Long service leave in advance</p><p><strong>(i)</strong> If a Doctor has completed ten years&#39; Continuous Service, a Health Service may, by agreement with the Doctor, grant long service leave in advance on a pro rata basis. The Health Service will not unreasonably withhold agreement.</p><p><strong>(ii)</strong> Supplementary to subclause 55.4(c)(i), if a Doctor requests to take long service leave on a pro rata basis under subclause 55.2(b), the Health Service must grant the Doctor&#39;s request to take long service leave as soon as practicable after receiving the request unless the Health Service has reasonable business grounds for refusing the request.</p><p><strong>(e)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> A Health Service may approve an application by a Doctor to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> Doctors should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 55.4(e). The Health Service will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iii)</strong> The Health Service, if requested by the Doctor, will provide information as to the amount of tax the Health Service intends to deduct where payment of long service leave is sought under subclause 55.4(e)(i).</p><p><strong>(iv)</strong> If granting the request under this subclause would result in an additional cost to the Health Service, the Health Service may refuse the Doctor&#39;s request.</p><p><strong>(v)</strong> Flexible taking of long service leave does not affect a Doctor&#39;s period of Continuous Service recognised. For example, a Doctor taking 12 months of long service leave at half pay will, for the purpose of calculating continuous service, have six months of continuous service recognised. A Doctor taking three months at double pay will have 6 months of Continuous Service recognised. In either case service will not be broken.</p><p><strong>55.5</strong> Payment on termination of employment</p><p><strong>(a)</strong> Basic entitlement at termination of employment</p><p>Except where an election is made under subclause 55.5(b) below, a Doctor with an entitlement to long service leave under subclause 55.2 is entitled to</p><p>payment in lieu of untaken long service leave upon termination of employment, calculated one thirtieth of the period of Continuous Service.</p><p><strong>(b)</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> A Doctor who has an entitlement to take long service leave on a pro rata basis under subclause 55.2(b) (who therefore has less than 15 years&#39; continuous service) and who intends to be re- employed by another Institution or Statutory Body may:</p><p>A. request in writing that payment for accrued long service leave be deferred until after the Doctor’s Allowable Period of Absence (as defined above) has expired; and</p><p>B. where the Doctor notifies the initial Health Service in writing within the Allowable Period of Absence that the Doctor has been employed as a Doctor by another Institution or Statutory Body, the initial Health Service is no longer required to make payment to the Doctor in respect of such service.</p><p><strong>(ii)</strong> Where the notice referred to at 55.5(b)(i)B is not provided prior to or within the Allowable Period of Absence, the Health Service will, upon the expiration of the allowable period of absence, make payment in lieu of long service leave as per subclause 55.5(a).</p><p><strong>(iii)</strong> For the removal of doubt, a Doctor who has an entitlement to take long service leave under subclause 55.2(a) may not make an election under this clause in respect of that entitlement.</p><p><strong>(c)</strong> Payment in lieu of long service leave on the death of a Doctor</p><p>Where a Doctor who has an entitlement to long service leave (or pro rata long service leave) under subclause 55.2 dies while still in the employ of the Health Service, payment in lieu of long service leave will be made to the Doctor’s personal representative equal to that in subclause 55.5(a) above.</p><p><strong>55.6</strong> Public holidays</p><p>Long service leave is inclusive of (not additional to) Public Holidays that occur during the relevant period of leave.</p><p><strong>55.7</strong> Transitional Arrangements for Parental Leave taken after 1 November 2018 and before the commencement date of this Agreement</p><p>Note 1: Unpaid Parental Leave taken prior to 1 November 2018 does not count as Continuous Service unless otherwise agreed, per subclause 54.5(e).</p><p>Note 2: Unpaid Parental Leave taken after the commencement date of this Agreement will constitute Continuous Service, per subclause 54.5(e).</p><p><strong>(a)</strong> As an exception to subclause 55.3(b), a Doctor who took a period of unpaid Parental Leave that included any part of the period between 1 November 2018 and the commencement date of this Agreement (inclusive) may make an application to the Health Service to have that service recognised for Long Service Leave purposes. The Health Service will approve the application and provide to the Doctor an updated Certificate of Service reflecting the adjusted service arrangements.</p><p><strong>(b)</strong> A Doctor electing to make an application under subclause 55.7(a) must make the application to the Health Service no later than 6 months of the following (whichever occurs last):</p><p><strong>(i)</strong> the date on which this Agreement commences; or</p><p><strong>(ii)</strong> the date on which the Doctor returns to work after the qualifying period of unpaid Parental Leave</p><p><strong>(c)</strong> This subclause 55.7 shall also apply to a Doctor in respect of a former Health Service if the Doctor took a qualifying unpaid period of Parental Leave under this clause while employed by that former Health Service.</p><p><strong>55.8</strong> Records</p><p>The Health Service will keep a long service leave record for each Doctor, containing particulars of service, leave taken and payments made.</p><p><strong>55.9</strong> Protection of pre-existing entitlement</p><p><strong>(a)</strong> No Doctor shall suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause</p><p>Plain language terms: LSL.</p>',122)])])}const g=t(r,[["render",i]]);export{d as __pageData,g as default};
